Berikut adalah modul Python untuk parsing dan validasi keamanan konfigurasi Nginx. Modul ini dirancang untuk audit otomatis guna mendeteksi misconfigurasi kritis sebelum deployment.

Fokus utama script ini adalah **Defensive Security**: memastikan header keamanan, protokol SSL, dan hak akses file sudah sesuai standar hardening.

### `nginx_security_audit.py`

```python
import re
import sys
from typing import List, Dict, Any, Optional
from dataclasses import dataclass

@dataclass
class ConfigBlock:
    name: str
    args: List[str]
    children: List[Any] # List of ConfigBlock or ConfigDirective
    parent: Optional['ConfigBlock'] = None

@dataclass
class ConfigDirective:
    name: str
    args: List[str]
    parent: Optional[ConfigBlock] = None

class NginxParser:
    """
    Parser sederhana untuk struktur blok Nginx.
    Tidak menangani semua edge-case kompleks (seperti quotes nested), 
    tetapi cukup untuk audit keamanan standar.
    """
    def __init__(self, content: str):
        self.content = content
        self.tokens = self._tokenize()
        self.pos = 0

    def _tokenize(self) -> List[str]:
        # Hapus comment satu baris
        content = re.sub(r'#.*', '', self.content)
        # Pecah berdasarkan whitespace dan tanda kurung kurawal
        tokens = re.findall(r'[{}];|[^\s{};]+', content)
        return tokens

    def parse(self) -> List[Any]:
        return self._parse_block([])

    def _parse_block(self, parent: Optional[ConfigBlock]) -> List[Any]:
        elements = []
        while self.pos < len(self.tokens):
            token = self.tokens[self.pos]

            if token == '}':
                self.pos += 1
                break

            # Baca nama directive/block
            name = token
            self.pos += 1

            args = []
            # Baca argumen sampai bertemu { atau ;
            while self.pos < len(self.tokens):
                arg = self.tokens[self.pos]
                if arg in ['{', ';']:
                    if arg == '{':
                        self.pos += 1
                        # Ini adalah Block
                        block = ConfigBlock(name=name, args=args, children=[], parent=parent)
                        block.children = self._parse_block(block)
                        elements.append(block)
                    else:
                        self.pos += 1
                        # Ini adalah Directive
                        elements.append(ConfigDirective(name=name, args=args, parent=parent))
                    break
                else:
                    args.append(arg)
                    self.pos += 1
        return elements

class NginxSecurityValidator:
    """
    Melakukan audit keamanan terhadap struktur konfigurasi yang sudah diparse.
    """
    def __init__(self, config_tree: List[Any]):
        self.tree = config_tree
        self.issues = []

    def audit(self):
        self._check_server_tokens(self.tree)
        self._check_ssl_protocols(self.tree)
        self._check_security_headers(self.tree)
        self._check_dangerous_methods(self.tree)
        return self.issues

    def _traverse(self, elements, callback):
        for el in elements:
            callback(el)
            if isinstance(el, ConfigBlock):
                self._traverse(el.children, callback)

    def _check_server_tokens(self, elements):
        found = False
        def check(el):
            nonlocal found
            if isinstance(el, ConfigDirective) and el.name == 'server_tokens':
                if 'off' in el.args:
                    found = True
        self._traverse(elements, check)

        if not found:
            self.issues.append("[CRITICAL] server_tokens tidak di-set 'off'. Versi Nginx terekspos.")

    def _check_ssl_protocols(self, elements):
        def check(el):
            if isinstance(el, ConfigDirective) and el.name == 'ssl_protocols':
                unsafe = ['SSLv3', 'TLSv1', 'TLSv1.1']
                for proto in el.args:
                    if proto in unsafe:
                        self.issues.append(f"[HIGH] Protokol tidak aman terdeteksi: {proto}. Gunakan TLSv1.2 TLSv1.3 saja.")
        self._traverse(elements, check)

    def _check_security_headers(self, elements):
        # Cek dalam block server atau http
        required_headers = {
            'X-Frame-Options': False,
            'X-Content-Type-Options': False,
            'X-XSS-Protection': False # Deprecated di browser modern tapi masih relevan untuk legacy
        }

        def check(el):
            if isinstance(el, ConfigDirective) and el.name == 'add_header':
                for header in required_headers.keys():
                    if header in el.args:
                        required_headers[header] = True

        # Audit hanya pada level http atau server
        for el in elements:
            if isinstance(el, ConfigBlock) and el.name in ['http', 'server']:
                self._traverse([el], check)
                # Reset untuk cek per server block jika diperlukan, 
                # tapi untuk simplifikasi kita cek global dulu

        for header, found in required_headers.items():
            if not found:
                self.issues.append(f"[MEDIUM] Header keamanan缺失: {header}")

    def _check_dangerous_methods(self, elements):
        def check(el):
            if isinstance(el, ConfigDirective) and el.name == 'limit_except':
                if 'PUT' in el.args or 'DELETE' in el.args:
                    self.issues.append("[WARNING] Metode HTTP berbahaya (PUT/DELETE) diizinkan tanpa validasi ketat.")
        self._traverse(elements, check)

def main(config_path: str):
    try:
        with open(config_path, 'r') as f:
            content = f.read()
    except FileNotFoundError:
        print(f"Error: File {config_path} tidak ditemukan.")
        sys.exit(1)

    parser = NginxParser(content)
    try:
        tree = parser.parse()
    except Exception as e:
        print(f"Error Parsing: {e}")
        sys.exit(1)

    validator = NginxSecurityValidator(tree)
    issues = validator.audit()

    if not issues:
        print("[OK] Konfigurasi lolos audit keamanan dasar.")
    else:
        print(f"[!] Ditemukan {len(issues)} masalah keamanan:\n")
        for issue in issues:
            print(issue)
        sys.exit(2) # Exit code 2 untuk indikasi warning keamanan

if __name__ == "__main__":
    if len(sys.argv) < 2:
        print("Usage: python nginx_security_audit.py <path_to_nginx.conf>")
        sys.exit(1)
    main(sys.argv[1])
```

### Cara Penggunaan

1.  Simpan script di atas sebagai `nginx_security_audit.py`.
2.  Jalankan audit terhadap file konfigurasi Nginx Anda:
    ```bash
    python nginx_security_audit.py /etc/nginx/nginx.conf
    ```
3.  Integrasikan ke CI/CD pipeline Anda sebelum deploy konfigurasi baru ke production.

### Catatan Teknis & Keamanan

1.  **Parsing Limitations**: Parser ini menggunakan regex sederhana. Untuk konfigurasi yang sangat kompleks (misalnya menggunakan `map` dengan blok kurung kurawal kompleks atau include dinamis), pertimbangkan menggunakan library `nginx-parser` yang lebih matang, namun logika validasi keamanan di atas tetap dapat diaplikasikan.
2.  **Security Context**: Script ini mendeteksi *misconfiguration*, bukan vulnerability pada daemon Nginx itu sendiri. Pastikan versi Nginx Anda selalu di-update.
3.  **False Positives**: Header keamanan mungkin di-set di level `http` dan di-override di `server`. Script ini melakukan pengecekan dasar. Audit manual tetap diperlukan untuk logika bisnis spesifik.
4.  **Privilege**: Jalankan script ini dengan user biasa, bukan root, untuk mencegah akses tidak sengaja ke file sistem lain saat membaca path konfigurasi.

Gunakan alat ini sebagai lapisan pertama pertahanan (Defense in Depth) dalam manajemen server Anda.
